/**
 * Convert a hex color to a light tinted version (for button backgrounds).
 * Works by mixing the color with white at ~90% white.
 */
function hexToLight(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  // Mix with white (255) at 85% white
  const lr = Math.round(r + (255 - r) * 0.85);
  const lg = Math.round(g + (255 - g) * 0.85);
  const lb = Math.round(b + (255 - b) * 0.85);
  return `rgb(${lr}, ${lg}, ${lb})`;
}

/**
 * Generate a random color that has enough contrast against existing colors.
 * Uses HSL to ensure vivid, distinguishable hues.
 */
function generateOverflowColor(existingColors, index) {
  // Golden angle hue spacing starting from a high offset to avoid clashing with defaults
  const hue = (index * 137.508 + 200) % 360;
  return `hsl(${Math.round(hue)}, 65%, 50%)`;
}

