// =============================================================================
// AGGREGATE DATASET BUILDER
// =============================================================================
// Combines all Kickoff datasets into one and all Exit datasets into one.
// The aggregation sums raw response counts, so percentages are naturally
// weighted by sample size (larger cohorts contribute more, as they should).

function buildAggregates() {
  // Group datasets by their type field
  const groups = { Kickoff: [], Exit: [] };
  DATA.datasets.forEach(ds => {
    if (groups[ds.type]) groups[ds.type].push(ds);
  });

  // For each type that has data, sum counts across all datasets
  return Object.entries(groups)
    .filter(([, list]) => list.length > 0)
    .map(([type, list]) => {
      const questions = {};
      DATA.questions.forEach(q => {
        questions[q] = {};
        DATA.likertScale.forEach(likert => {
          // Sum this Likert response across all datasets of this type
          questions[q][likert] = list.reduce(
            (sum, ds) => sum + (ds.questions[q]?.[likert] || 0), 0
          );
        });
      });
      return {
        name: `All ${type}s Combined`,
        type,
        cohort: `All ${type}s`,
        n: list.reduce((sum, ds) => sum + ds.n, 0),
        questions,
      };
    });
}

const AGGREGATE_DATASETS = buildAggregates();


// =============================================================================
// STATISTICS & CURVE FIT FUNCTIONS
// =============================================================================

/**
 * Compute mean, standard deviation, and total from a question's Likert counts.
 * This is the foundation for all three fit methods.
 *
 * @param {Object} counts - e.g. {"Very untrue of me": 10, "Neutral": 30, ...}
 * @returns {{ mean: number, std: number, total: number }}
 */
function computeStats(counts) {
  const total = Object.values(counts).reduce((a, b) => a + b, 0);
  if (total === 0) return { mean: 0, std: 1, total: 0 };

  // Weighted mean: Σ(value × count) / total
  let sum = 0, sumSq = 0;
  DATA.likertScale.forEach((label, i) => {
    const val = LIKERT_NUMERIC[i];
    const c = counts[label] || 0;
    sum += val * c;
    sumSq += val * val * c;
  });
  const mean = sum / total;

  // Variance: E[X²] - (E[X])², floored at 0.01 to avoid division by zero
  const variance = Math.max(sumSq / total - mean * mean, 0.01);
  return { mean, std: Math.sqrt(variance), total };
}

/**
 * Standard Gaussian (normal distribution) probability density function.
 * Used by Method of Moments and Least Squares fits.
 *
 * @param {number} x - Point to evaluate
 * @param {number} mean - Distribution mean (μ)
 * @param {number} std - Distribution standard deviation (σ)
 * @returns {number} PDF value at x
 */
function gaussianPDF(x, mean, std) {
  const s = Math.max(std, 0.05); // floor to prevent division by zero
  return (1 / (s * Math.sqrt(2 * Math.PI))) * Math.exp(-0.5 * ((x - mean) / s) ** 2);
}


// -----------------------------------------------------------------------------
// FIT METHOD 1: Method of Moments (MoM)
// -----------------------------------------------------------------------------
// The simplest approach: compute mean and std directly from the data,
// then evaluate the normal PDF with those parameters.
//
// Pros: instant to compute, produces clean μ and σ for reporting
// Cons: assumes symmetry, can't capture skew (e.g. LinkedIn profile kickoff)

/**
 * @param {Object} counts - Likert response counts
 * @param {number[]} xCurve - Array of x values to evaluate (e.g. -2.8 to 2.8)
 * @returns {{ y: number[], annotation: string }}
 */
function fitMethodOfMoments(counts, xCurve, usePercent = true) {
  const { mean, std, total } = computeStats(counts);
  if (total === 0) return { y: xCurve.map(() => 0), annotation: "" };

  // Scale: PDF × 100 for %, PDF × total for raw counts
  const scale = usePercent ? 100 : total;
  const y = xCurve.map(x => gaussianPDF(x, mean, std) * scale);
  return { y, annotation: `\u03BC=${mean.toFixed(2)}, \u03C3=${std.toFixed(2)}` };
}


// -----------------------------------------------------------------------------
// FIT METHOD 2: Least Squares Gaussian Fit
// -----------------------------------------------------------------------------
// Finds the amplitude, mean, and std that minimize the squared error between
// the Gaussian curve and the 5 observed percentage bars.
//
// Uses a grid search over (μ, σ) with the optimal amplitude solved
// analytically for each pair. With only 5 data points and 2 shape parameters,
// a grid search is fast and guaranteed to find the global optimum, unlike
// gradient descent which can get stuck on skewed distributions.
//
// Pros: hugs the actual bar heights more closely than MoM
// Cons: still forces symmetry (it's a Gaussian), slightly more computation

function fitLeastSquares(counts, xCurve, usePercent = true) {
  const total = Object.values(counts).reduce((a, b) => a + b, 0);
  if (total === 0) return { y: xCurve.map(() => 0), annotation: "" };

  // Observed bar heights at the 5 Likert positions (in whatever scale the bars use)
  const scale = usePercent ? 100 : total;
  const observed = DATA.likertScale.map(
    label => ((counts[label] || 0) / total) * scale
  );

  // Grid search: try many (mu, sigma) combinations.
  // For each pair, the optimal amplitude can be solved in closed form:
  //   amp = Σ(observed_i * g_i) / Σ(g_i^2)
  // where g_i = gaussianPDF(x_i, mu, sigma)
  let bestMu = 0, bestSigma = 1, bestAmp = 1, bestError = Infinity;

  // Search mu from -2.5 to 2.5 in steps of 0.1, sigma from 0.2 to 3.0 in steps of 0.1
  for (let mu = -2.5; mu <= 2.5; mu += 0.1) {
    for (let sigma = 0.2; sigma <= 3.0; sigma += 0.1) {
      // Evaluate Gaussian at the 5 Likert positions
      let sumOG = 0; // Σ(observed * gaussian)
      let sumGG = 0; // Σ(gaussian^2)
      for (let i = 0; i < 5; i++) {
        const g = gaussianPDF(LIKERT_NUMERIC[i], mu, sigma);
        sumOG += observed[i] * g;
        sumGG += g * g;
      }

      // Optimal amplitude (least squares closed-form solution)
      if (sumGG < 1e-10) continue; // degenerate case
      const amp = Math.max(sumOG / sumGG, 0);

      // Compute total squared error for this (mu, sigma, amp)
      let sse = 0;
      for (let i = 0; i < 5; i++) {
        const predicted = amp * gaussianPDF(LIKERT_NUMERIC[i], mu, sigma);
        sse += (predicted - observed[i]) ** 2;
      }

      if (sse < bestError) {
        bestError = sse;
        bestMu = mu;
        bestSigma = sigma;
        bestAmp = amp;
      }
    }
  }

  const y = xCurve.map(x => bestAmp * gaussianPDF(x, bestMu, bestSigma));
  return { y, annotation: `\u03BC=${bestMu.toFixed(2)}, \u03C3=${bestSigma.toFixed(2)}` };
}


// -----------------------------------------------------------------------------
// FIT METHOD 3: Kernel Density Estimation (KDE)
// -----------------------------------------------------------------------------
// Nonparametric: places a small Gaussian "kernel" at every data point and
// sums them to get a smooth density estimate. Captures skew, bimodality,
// and any shape the data actually has.
//
// Since our data is discrete (5 Likert values), we expand the counts into
// individual observations and apply Silverman's bandwidth rule.
//
// Pros: faithful to the actual data shape, no symmetry assumption
// Cons: can look bumpy, no clean μ/σ to report

function fitKDE(counts, xCurve, minBandwidth = 0.7, usePercent = true) {
  const total = Object.values(counts).reduce((a, b) => a + b, 0);
  if (total === 0) return { y: xCurve.map(() => 0), annotation: "" };

  // Expand counts into a raw data array
  // e.g. if "Neutral" has count 30, we add thirty 0s to the array
  const raw = [];
  DATA.likertScale.forEach((label, i) => {
    const count = counts[label] || 0;
    for (let j = 0; j < count; j++) raw.push(LIKERT_NUMERIC[i]);
  });

  if (raw.length < 2) return { y: xCurve.map(() => 0), annotation: "n/a" };

  // Compute standard deviation of the raw data
  const n = raw.length;
  const mean = raw.reduce((a, b) => a + b, 0) / n;
  const variance = raw.reduce((a, b) => a + (b - mean) ** 2, 0) / n;
  const std = Math.sqrt(Math.max(variance, 0.01));

  // Silverman's rule of thumb for bandwidth selection:
  // h = 0.9 * min(std, IQR/1.34) * n^(-1/5)
  //
  // For discrete Likert data with spacing of 1.0 between values, Silverman's
  // rule often picks a bandwidth smaller than the gap, which creates separate
  // peaks at each Likert value (multimodal bumps). Flooring at 0.7 ensures
  // adjacent kernels merge into a single smooth peak while still capturing
  // skew and asymmetry. Increase this value for smoother curves, decrease
  // for more sensitivity to the individual bar heights.
  const bandwidth = Math.max(0.9 * std * Math.pow(n, -0.2), minBandwidth);

  // Evaluate KDE: sum of Gaussian kernels centered at each data point
  const scale = usePercent ? 100 : total;
  const y = xCurve.map(x => {
    let density = 0;
    for (let k = 0; k < n; k++) {
      density += gaussianPDF(x, raw[k], bandwidth);
    }
    // Normalize to density, then scale to match bar heights (% or count)
    return (density / n) * scale;
  });

  return { y, annotation: `\u03BC=${mean.toFixed(2)}, bw=${bandwidth.toFixed(2)}` };
}

/**
 * Registry of all fit methods. Used by the UI toggle and the chart components.
 * To add a new fit method, implement the function and add it here.
 */
const FIT_METHODS = {
  mom:  { fn: fitMethodOfMoments, label: "Method of Moments" },
  lsq:  { fn: fitLeastSquares,    label: "Least Squares" },
  kde:  { fn: fitKDE,             label: "KDE" },
  none: { fn: null,               label: "None" },
};


/**
 * Compute Silverman's and Scott's rule bandwidth for a given Likert count distribution.
 *
 * Silverman's rule: h = 0.9 * min(σ, IQR/1.34) * n^(-1/5)
 * Scott's rule:     h = 3.49 * σ * n^(-1/3)
 *
 * Both are designed for continuous data, so they tend to undersmooth our discrete
 * 5-point Likert data, which is why we need the bandwidth floor slider.
 *
 * @param {Object} counts - Likert response counts
 * @returns {{ silverman: number, scott: number } | null}
 */
function computeBandwidthRules(counts) {
  // Expand to raw data
  const raw = [];
  DATA.likertScale.forEach((label, i) => {
    const c = counts[label] || 0;
    for (let j = 0; j < c; j++) raw.push(LIKERT_NUMERIC[i]);
  });
  const n = raw.length;
  if (n < 2) return null;

  const mean = raw.reduce((a, b) => a + b, 0) / n;
  const std = Math.sqrt(raw.reduce((a, b) => a + (b - mean) ** 2, 0) / n);

  // IQR: sort and pick 25th/75th percentile
  const sorted = [...raw].sort((a, b) => a - b);
  const q1 = sorted[Math.floor(n * 0.25)];
  const q3 = sorted[Math.floor(n * 0.75)];
  const iqr = q3 - q1;

  // Silverman: 0.9 * min(std, IQR/1.34) * n^(-1/5)
  const silverman = 0.9 * Math.min(std, (iqr || std) / 1.34) * Math.pow(n, -0.2);

  // Scott: 3.49 * std * n^(-1/3)
  const scott = 3.49 * std * Math.pow(n, -1 / 3);

  return { silverman, scott };
}


