// =============================================================================
// INFO TOOLTIP COMPONENT
// =============================================================================
// Reusable hover tooltip used throughout the dashboard: curve fit buttons,
// bandwidth anchors, and question titles. Shows a styled popup above the
// wrapped element on hover.

function InfoTooltip({ text, children, width = 260, position = "above" }) {
  const [show, setShow] = useState(false);
  const triggerRef = useRef(null);
  const [coords, setCoords] = useState({ top: 0, left: 0 });
  const isBelow = position === "below";

  // Recalculate position when showing, using the trigger's bounding rect.
  // position: fixed escapes all parent overflow/clipping contexts.
  useEffect(() => {
    if (show && triggerRef.current) {
      const rect = triggerRef.current.getBoundingClientRect();
      setCoords({
        left: rect.left + rect.width / 2,
        top: isBelow ? rect.bottom + 8 : rect.top - 8,
      });
    }
  }, [show, isBelow]);

  return (
    <div
      ref={triggerRef}
      style={{ position: "relative", display: "inline-block" }}
      onMouseEnter={() => setShow(true)}
      onMouseLeave={() => setShow(false)}
    >
      {children}
      {show && (
        <div style={{
          position: "fixed",
          top: isBelow ? coords.top : "auto",
          bottom: isBelow ? "auto" : `calc(100vh - ${coords.top}px)`,
          left: coords.left,
          transform: "translateX(-50%)",
          width,
          padding: "10px 12px",
          background: "#1e1e2e",
          color: "#e0e0e0",
          fontSize: 11,
          lineHeight: 1.5,
          borderRadius: 8,
          boxShadow: "0 4px 20px rgba(0,0,0,0.25)",
          zIndex: 1000,
          pointerEvents: "none",
        }}>
          {text}
          <div style={{
            position: "absolute",
            ...(isBelow
              ? { bottom: "100%", borderBottom: "6px solid #1e1e2e", borderTop: "none" }
              : { top: "100%", borderTop: "6px solid #1e1e2e", borderBottom: "none" }
            ),
            left: "50%",
            transform: "translateX(-50%)",
            width: 0, height: 0,
            borderLeft: "6px solid transparent",
            borderRight: "6px solid transparent",
          }} />
        </div>
      )}
    </div>
  );
}


// =============================================================================
// COLOR PICKER COMPONENT
// =============================================================================
// A small popover with ~20 color swatches. Click the trigger (a colored square)
// to open, click a swatch to apply, click outside or the trigger again to close.

function ColorPicker({ currentColor, onSelect }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    const handleClick = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  return (
    <div ref={ref} style={{ position: "relative", display: "inline-block" }}>
      {/* Trigger: the colored square */}
      <div
        onClick={(e) => { e.stopPropagation(); setOpen(!open); }}
        style={{
          width: 14, height: 14, borderRadius: 3,
          background: currentColor,
          cursor: "pointer",
          border: "2px solid rgba(255,255,255,0.8)",
          boxShadow: "0 0 0 1px rgba(0,0,0,0.15)",
          transition: "transform 0.1s",
          transform: open ? "scale(1.2)" : "scale(1)",
        }}
        title="Click to change color"
      />
      {/* Swatch popover */}
      {open && (
        <div style={{
          position: "absolute",
          top: "calc(100% + 6px)",
          left: 0,
          background: "#1e1e2e",
          borderRadius: 8,
          padding: 8,
          boxShadow: "0 4px 20px rgba(0,0,0,0.3)",
          zIndex: 150,
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)",
          gap: 4,
          width: 140,
        }}>
          {COLOR_SWATCHES.map(color => (
            <div
              key={color}
              onClick={(e) => {
                e.stopPropagation();
                onSelect(color);
                setOpen(false);
              }}
              style={{
                width: 22, height: 22, borderRadius: 4,
                background: color,
                cursor: "pointer",
                border: color === currentColor
                  ? "2px solid #fff"
                  : "2px solid transparent",
                transition: "transform 0.1s",
              }}
              onMouseEnter={e => e.target.style.transform = "scale(1.15)"}
              onMouseLeave={e => e.target.style.transform = "scale(1)"}
            />
          ))}
        </div>
      )}
    </div>
  );
}


